// NSubstitute (ít verbose hơn Moq)
public class OrderServiceTests
{
    private readonly IOrderRepository _repo = Substitute.For<IOrderRepository>();
    private readonly OrderService _sut;

    public OrderServiceTests() => _sut = new OrderService(_repo, TimeProvider.System);

    [Fact]
    public async Task CreateOrder_WithValidInput_ReturnsCreatedOrder()
    {
        // Arrange
        var dto = new CreateOrderDto(CustomerId: 1, ProductId: 42, Quantity: 2);
        _repo.CreateAsync(Arg.Any<Order>(), Arg.Any<CancellationToken>())
            .Returns(new Order { Id = 100, Status = "pending" });

        // Act
        var result = await _sut.CreateAsync(dto, CancellationToken.None);

        // Assert (FluentAssertions)
        result.Should().NotBeNull();
        result.Id.Should().Be(100);
        result.Status.Should().Be("pending");
    }

    [Theory]
    [InlineData(0, "Quantity phải > 0")]
    [InlineData(-1, "Quantity phải > 0")]
    [InlineData(101, "Quantity tối đa 100")]
    public async Task CreateOrder_WithInvalidQuantity_ThrowsValidationException(
        int quantity, string expectedMessage)
    {
        var dto = new CreateOrderDto(1, 1, quantity);
        var act = () => _sut.CreateAsync(dto, CancellationToken.None);
        await act.Should().ThrowAsync<ValidationException>()
            .WithMessage($"*{expectedMessage}*");
    }
}
